            val tokenBytes = ByteArray(32)
            System.arraycopy(hash, 0, tokenBytes, 0, 32)
            Base64.encodeToString(tokenBytes, Base64.URL_SAFE or Base64.NO_WRAP).also { encodedToken ->
                // Replace '+' and '/' for security purposes.
                return encodedToken.replace('+', '-').replace('/', '_')
